export const dynamic = 'force-dynamic';

/**
 * Concept Mastery API
 * GET  /api/lms/mastery?conceptId=xxx → returns mastery state for one concept
 * GET  /api/lms/mastery → returns all mastery states for the student
 * POST /api/lms/mastery → updates mastery using FSRS engine
 *
 * SEC-HARDENING: Wrapped with withUserGuard for centralized auth + CSRF + rate limiting.
 */
import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { withUserGuard } from '@/lib/user-api-guard';
import { prisma } from '@/lib/db';
import {
  scheduleReview,
  quizScoreToRating,
  createNewCard,
  type FsrsCard,
  type Rating,
} from '@/lib/lms/fsrs-engine';

const updateMasterySchema = z.object({
  conceptId: z.string().min(1),
  quizScore: z.number().min(0).max(100),
  rating: z.number().min(1).max(4).optional(), // FSRS rating 1-4; auto-derived from quizScore if omitted
  passingScore: z.number().min(0).max(100).optional().default(70),
});

export const GET = withUserGuard(async (request: NextRequest, { session }) => {
  const tenantId = session.user.tenantId;
  if (!tenantId) {
    return NextResponse.json({ error: 'No tenant context' }, { status: 403 });
  }

  const { searchParams } = new URL(request.url);
  const conceptId = searchParams.get('conceptId');
  const view = searchParams.get('view'); // 'dashboard' returns full concept grid
  const userId = session.user.id!;

  if (conceptId) {
    // Return mastery for a single concept
    const mastery = await prisma.lmsConceptMastery.findUnique({
      where: { tenantId_userId_conceptId: { tenantId, userId, conceptId } },
      include: {
        concept: { select: { id: true, name: true, domain: true, targetBloomLevel: true, description: true, difficulty: true, estimatedMinutes: true } },
      },
    });

    if (!mastery) {
      // Still return the concept info even if no mastery record
      const concept = await prisma.lmsConcept.findFirst({
        where: { id: conceptId, tenantId, isActive: true },
        select: { id: true, slug: true, name: true, description: true, domain: true, targetBloomLevel: true, difficulty: true, estimatedMinutes: true },
      });
      return NextResponse.json({
        mastery: null,
        concept: concept ?? null,
        message: 'No mastery record yet for this concept',
      });
    }

    return NextResponse.json({ mastery: formatMastery(mastery) });
  }

  // Dashboard view: return ALL concepts (including untested) with mastery grid
  if (view === 'dashboard') {
    const [concepts, masteries] = await Promise.all([
      prisma.lmsConcept.findMany({
        where: { tenantId, isActive: true },
        select: {
          id: true, slug: true, name: true, description: true,
          domain: true, targetBloomLevel: true, difficulty: true, estimatedMinutes: true,
        },
        orderBy: [{ domain: 'asc' }, { name: 'asc' }],
        take: 500,
      }),
      prisma.lmsConceptMastery.findMany({
        where: { tenantId, userId },
        select: {
          conceptId: true, currentLevel: true, confidence: true,
          interval: true, reviewCount: true, nextReviewAt: true,
          lastTestedAt: true, lastCorrectAt: true,
          totalAttempts: true, totalCorrect: true, strengthHistory: true,
        },
        take: 500,
      }),
    ]);

    const masteryMap = new Map(masteries.map(m => [m.conceptId, m]));
    const now = new Date();

    const conceptGrid = concepts.map(concept => {
      const m = masteryMap.get(concept.id);
      let status: 'untested' | 'weak' | 'in_progress' | 'mastered';
      if (!m || m.currentLevel === 0) {
        status = 'untested';
      } else if (m.currentLevel <= 1 || m.confidence < 0.3) {
        status = 'weak';
      } else if (m.currentLevel < concept.targetBloomLevel || m.confidence < 0.7) {
        status = 'in_progress';
      } else {
        status = 'mastered';
      }
      return {
        ...concept,
        mastery: m ? {
          currentLevel: m.currentLevel,
          confidence: m.confidence,
          reviewCount: m.reviewCount,
          nextReviewAt: m.nextReviewAt?.toISOString() ?? null,
          lastTestedAt: m.lastTestedAt?.toISOString() ?? null,
          totalAttempts: m.totalAttempts,
          totalCorrect: m.totalCorrect,
          strengthHistory: m.strengthHistory,
        } : null,
        status,
      };
    });

    const reviewQueue = conceptGrid
      .filter(c => c.mastery?.nextReviewAt && new Date(c.mastery.nextReviewAt) <= now)
      .sort((a, b) => {
        const aTime = a.mastery?.nextReviewAt ? new Date(a.mastery.nextReviewAt).getTime() : 0;
        const bTime = b.mastery?.nextReviewAt ? new Date(b.mastery.nextReviewAt).getTime() : 0;
        return aTime - bTime;
      })
      .slice(0, 20);

    const stats = {
      total: conceptGrid.length,
      mastered: conceptGrid.filter(c => c.status === 'mastered').length,
      inProgress: conceptGrid.filter(c => c.status === 'in_progress').length,
      weak: conceptGrid.filter(c => c.status === 'weak').length,
      untested: conceptGrid.filter(c => c.status === 'untested').length,
      dueForReview: reviewQueue.length,
    };

    const domains = [...new Set(concepts.map(c => c.domain))].sort();

    return NextResponse.json({ concepts: conceptGrid, reviewQueue, stats, domains });
  }

  // Default: return all mastery states for the student (only tested concepts)
  const masteries = await prisma.lmsConceptMastery.findMany({
    where: { tenantId, userId },
    include: {
      concept: { select: { id: true, name: true, domain: true, targetBloomLevel: true } },
    },
    orderBy: { updatedAt: 'desc' },
    take: 200,
  });

  return NextResponse.json({
    masteries: masteries.map(formatMastery),
    total: masteries.length,
  });
}, { skipCsrf: true });

export const POST = withUserGuard(async (request: NextRequest, { session }) => {
  const tenantId = session.user.tenantId;
  if (!tenantId) {
    return NextResponse.json({ error: 'No tenant context' }, { status: 403 });
  }

  const body = await request.json();
  const parsed = updateMasterySchema.safeParse(body);
  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid mastery update data' }, { status: 400 });
  }

  const { conceptId, quizScore, passingScore } = parsed.data;
  const userId = session.user.id!;

  // Verify concept exists
  const concept = await prisma.lmsConcept.findFirst({
    where: { id: conceptId, tenantId, isActive: true },
    select: { id: true, name: true, targetBloomLevel: true },
  });

  if (!concept) {
    return NextResponse.json({ error: 'Concept not found' }, { status: 404 });
  }

  // Get or create mastery record
  let mastery = await prisma.lmsConceptMastery.findUnique({
    where: { tenantId_userId_conceptId: { tenantId, userId, conceptId } },
  });

  // Determine FSRS rating from quiz score (or use explicit rating)
  const rating: Rating = (parsed.data.rating as Rating) ?? quizScoreToRating(quizScore, passingScore!);

  // Build FSRS card from mastery record
  const card: FsrsCard = mastery
    ? {
        difficulty: mastery.easiness, // Map easiness to FSRS difficulty
        stability: mastery.interval,
        retrievability: mastery.confidence,
        lastReview: mastery.lastTestedAt,
        interval: mastery.interval,
        reps: mastery.reviewCount,
        lapses: mastery.totalAttempts - mastery.totalCorrect,
      }
    : createNewCard();

  // Schedule next review using FSRS
  const now = new Date();
  const reviewResult = scheduleReview(card, rating, now);

  // Calculate new mastery level based on quiz score
  const isCorrect = quizScore >= passingScore!;
  const newLevel = isCorrect
    ? Math.min(5, (mastery?.currentLevel ?? 0) + 1)
    : Math.max(0, (mastery?.currentLevel ?? 0) - 1);

  // Update or create mastery record
  const updatedMastery = await prisma.lmsConceptMastery.upsert({
    where: { tenantId_userId_conceptId: { tenantId, userId, conceptId } },
    create: {
      tenantId,
      userId,
      conceptId,
      currentLevel: newLevel,
      confidence: Math.min(1, quizScore / 100),
      easiness: reviewResult.newDifficulty,
      interval: reviewResult.interval,
      reviewCount: 1,
      nextReviewAt: reviewResult.nextReview,
      lastTestedAt: now,
      lastCorrectAt: isCorrect ? now : null,
      totalAttempts: 1,
      totalCorrect: isCorrect ? 1 : 0,
      strengthHistory: JSON.stringify([{
        date: now.toISOString(),
        level: newLevel,
        confidence: quizScore / 100,
        score: quizScore,
      }]),
    },
    update: {
      currentLevel: newLevel,
      confidence: Math.min(1, quizScore / 100),
      easiness: reviewResult.newDifficulty,
      interval: reviewResult.interval,
      reviewCount: { increment: 1 },
      nextReviewAt: reviewResult.nextReview,
      lastTestedAt: now,
      ...(isCorrect && { lastCorrectAt: now }),
      totalAttempts: { increment: 1 },
      totalCorrect: isCorrect ? { increment: 1 } : undefined,
    },
    include: {
      concept: { select: { id: true, name: true, domain: true, targetBloomLevel: true } },
    },
  });

  return NextResponse.json({
    mastery: formatMastery(updatedMastery),
    fsrs: {
      rating,
      nextReview: reviewResult.nextReview.toISOString(),
      interval: reviewResult.interval,
      newDifficulty: reviewResult.newDifficulty,
      newStability: reviewResult.newStability,
    },
  });
});

// ── Helpers ───────────────────────────────────────────────────────────

interface MasteryRecord {
  id: string;
  conceptId: string;
  currentLevel: number;
  confidence: number;
  interval: number;
  reviewCount: number;
  nextReviewAt: Date | null;
  lastTestedAt: Date | null;
  lastCorrectAt: Date | null;
  totalAttempts: number;
  totalCorrect: number;
  concept?: { id: string; name: string; domain: string; targetBloomLevel: number } | null;
}

function formatMastery(m: MasteryRecord) {
  return {
    id: m.id,
    conceptId: m.conceptId,
    conceptName: m.concept?.name ?? null,
    domain: m.concept?.domain ?? null,
    currentLevel: m.currentLevel,
    targetLevel: m.concept?.targetBloomLevel ?? 3,
    confidence: m.confidence,
    interval: m.interval,
    reviewCount: m.reviewCount,
    nextReviewAt: m.nextReviewAt?.toISOString() ?? null,
    lastTestedAt: m.lastTestedAt?.toISOString() ?? null,
    lastCorrectAt: m.lastCorrectAt?.toISOString() ?? null,
    totalAttempts: m.totalAttempts,
    totalCorrect: m.totalCorrect,
    accuracyRate: m.totalAttempts > 0
      ? Math.round((m.totalCorrect / m.totalAttempts) * 100)
      : 0,
    isMastered: m.currentLevel >= (m.concept?.targetBloomLevel ?? 3),
  };
}

'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import { X, Mic, MicOff, Send, Sparkles, Volume2, VolumeX, Loader2 } from 'lucide-react';

/**
 * AURELIA WIDGET — Omnipresente sur chaque page etudiant
 *
 * Bouton flottant en bas a droite. Un clic ouvre la conversation.
 * Aurelia connait la page actuelle (cours, lecon, quiz) et adapte ses reponses.
 * Supporte texte ET voix (Deepgram STT + ElevenLabs TTS).
 */

interface AureliaWidgetProps {
  /** Contexte de la page actuelle — injecte dans chaque message a Aurelia */
  context?: {
    pageType: 'course' | 'lesson' | 'quiz' | 'dashboard' | 'catalog' | 'certificate' | 'general';
    courseId?: string;
    courseTitle?: string;
    lessonId?: string;
    lessonTitle?: string;
    lessonType?: string;
    conceptId?: string;
    conceptName?: string;
    quizId?: string;
    currentScore?: number;
    masteryLevel?: number;
  };
  /** Nom de l'etudiant pour personnalisation */
  studentName?: string;
  /** Province de l'etudiant (null = pas encore definie) */
  studentProvince?: string | null;
}

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
}

const PROVINCE_OPTIONS = [
  { code: 'AB', label: 'Alberta' },
  { code: 'BC', label: 'Colombie-Britannique' },
  { code: 'MB', label: 'Manitoba' },
  { code: 'NB', label: 'Nouveau-Brunswick' },
  { code: 'NL', label: 'Terre-Neuve-et-Labrador' },
  { code: 'NS', label: 'Nouvelle-Ecosse' },
  { code: 'NT', label: 'Territoires du Nord-Ouest' },
  { code: 'NU', label: 'Nunavut' },
  { code: 'ON', label: 'Ontario' },
  { code: 'PE', label: 'Ile-du-Prince-Edouard' },
  { code: 'QC', label: 'Quebec' },
  { code: 'SK', label: 'Saskatchewan' },
  { code: 'YT', label: 'Yukon' },
];

export default function AureliaWidget({ context, studentName, studentProvince }: AureliaWidgetProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [showPulse, setShowPulse] = useState(true);
  const [speakingMessageId, setSpeakingMessageId] = useState<string | null>(null);
  const [loadingTtsId, setLoadingTtsId] = useState<string | null>(null);
  const [autoSpeak, setAutoSpeak] = useState(false);
  const [showProvincePrompt, setShowProvincePrompt] = useState(!studentProvince);
  const [selectedProvince, setSelectedProvince] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const autoSpeakRef = useRef(autoSpeak);

  // Auto-scroll au dernier message
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Focus input quand ouvert
  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  // Keep autoSpeakRef in sync
  useEffect(() => {
    autoSpeakRef.current = autoSpeak;
  }, [autoSpeak]);

  // Cleanup audio on unmount
  useEffect(() => {
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  /** Stop any currently playing TTS audio */
  const stopSpeaking = useCallback(() => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
      audioRef.current = null;
    }
    setSpeakingMessageId(null);
  }, []);

  /** Speak a message via ElevenLabs TTS */
  const speakMessage = useCallback(async (messageId: string, text: string) => {
    // If already speaking this message, stop it
    if (speakingMessageId === messageId) {
      stopSpeaking();
      return;
    }

    // Stop any current playback
    stopSpeaking();

    // Strip markdown formatting for cleaner speech
    const cleanText = text
      .replace(/#{1,6}\s/g, '')        // headings
      .replace(/\*\*(.+?)\*\*/g, '$1') // bold
      .replace(/\*(.+?)\*/g, '$1')     // italic
      .replace(/`(.+?)`/g, '$1')       // inline code
      .replace(/\[(.+?)\]\(.+?\)/g, '$1') // links
      .replace(/^[-*]\s/gm, '')        // list markers
      .replace(/^\d+\.\s/gm, '')       // numbered lists
      .trim();

    if (!cleanText) return;

    setLoadingTtsId(messageId);

    try {
      const res = await fetch('/api/lms/tutor/tts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: cleanText.slice(0, 5000) }),
      });

      if (!res.ok) {
        const errorData = await res.json().catch(() => ({}));
        console.error('[TTS] Error:', errorData.error || res.statusText);
        return;
      }

      const audioBlob = await res.blob();
      const audioUrl = URL.createObjectURL(audioBlob);
      const audio = new Audio(audioUrl);

      audio.onended = () => {
        setSpeakingMessageId(null);
        URL.revokeObjectURL(audioUrl);
        audioRef.current = null;
      };

      audio.onerror = () => {
        setSpeakingMessageId(null);
        URL.revokeObjectURL(audioUrl);
        audioRef.current = null;
      };

      audioRef.current = audio;
      setSpeakingMessageId(messageId);
      await audio.play();
    } catch (err) {
      console.error('[TTS] Failed to speak:', err);
      setSpeakingMessageId(null);
    } finally {
      setLoadingTtsId(null);
    }
  }, [speakingMessageId, stopSpeaking]);

  // Message d'accueil contextuel
  useEffect(() => {
    if (isOpen && messages.length === 0) {
      const greeting = showProvincePrompt
        ? `Bonjour${studentName ? `, ${studentName}` : ''}! Je suis Aurelia, ta tutrice personnelle. Avant de commencer, j'ai besoin de savoir dans quelle province tu travailles — les lois et regulateurs varient d'une province a l'autre au Canada.`
        : getContextualGreeting();
      setMessages([{
        id: 'greeting',
        role: 'assistant',
        content: greeting,
        timestamp: new Date(),
      }]);
    }
  }, [isOpen]);

  function getContextualGreeting(): string {
    const name = studentName ? `, ${studentName}` : '';

    switch (context?.pageType) {
      case 'lesson':
        return `Salut${name}! Tu es sur la leçon "${context.lessonTitle}". Si tu as des questions sur le contenu, je suis là pour t'expliquer. 😊`;
      case 'quiz':
        return `Hey${name}! Tu es dans un quiz. Je ne peux pas te donner les réponses, mais je peux t'aider à comprendre les concepts si tu bloques. Demande-moi!`;
      case 'course':
        return `Bonjour${name}! Tu regardes le cours "${context.courseTitle}". Tu veux que je t'explique le contenu ou que je te recommande par où commencer?`;
      case 'dashboard':
        return `Salut${name}! Comment ça va aujourd'hui? Je vois ton tableau de bord — tu veux qu'on révise tes points faibles ou qu'on continue où tu en étais?`;
      case 'certificate':
        return `Félicitations${name}! 🎉 Tu as un certificat ici. Si tu veux revoir la matière ou préparer la suite, je suis là.`;
      default:
        return `Bonjour${name}! Je suis Aurélia, ta tutrice personnelle. Pose-moi n'importe quelle question sur ta formation. 💡`;
    }
  }

  async function sendMessage(content: string) {
    if (!content.trim() || isLoading) return;

    const userMessage: Message = {
      id: `user-${Date.now()}`,
      role: 'user',
      content: content.trim(),
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);
    setShowPulse(false);

    try {
      const res = await fetch('/api/lms/tutor/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          message: content.trim(),
          context,
          conversationHistory: messages.slice(-10).map(m => ({
            role: m.role,
            content: m.content,
          })),
        }),
      });

      const data = await res.json();

      const assistantId = `assistant-${Date.now()}`;
      const assistantContent = data.response || 'Désolée, je n\'ai pas pu traiter ta demande.';

      setMessages(prev => [...prev, {
        id: assistantId,
        role: 'assistant',
        content: assistantContent,
        timestamp: new Date(),
      }]);

      // Auto-speak if enabled
      if (autoSpeakRef.current) {
        // Small delay to let the state update propagate
        setTimeout(() => speakMessage(assistantId, assistantContent), 100);
      }
    } catch {
      setMessages(prev => [...prev, {
        id: `error-${Date.now()}`,
        role: 'assistant',
        content: 'Oops, problème de connexion. Réessaie dans un instant!',
        timestamp: new Date(),
      }]);
    } finally {
      setIsLoading(false);
    }
  }

  async function toggleVoice() {
    if (isListening) {
      setIsListening(false);
      // Stop recording — handled by browser MediaRecorder
      return;
    }

    setIsListening(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];

      mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
      mediaRecorder.onstop = async () => {
        stream.getTracks().forEach(t => t.stop());
        const blob = new Blob(chunks, { type: 'audio/webm' });

        // Envoyer a Deepgram pour STT
        const formData = new FormData();
        formData.append('audio', blob);

        try {
          const res = await fetch('/api/lms/tutor/stt', { method: 'POST', body: formData });
          const data = await res.json();
          if (data.text) {
            setInput(data.text);
            sendMessage(data.text);
          }
        } catch {
          // Fallback silencieux
        }
        setIsListening(false);
      };

      mediaRecorder.start();
      // Auto-stop apres 30 secondes
      setTimeout(() => {
        if (mediaRecorder.state === 'recording') {
          mediaRecorder.stop();
        }
      }, 30000);
    } catch {
      setIsListening(false);
    }
  }

  return (
    <>
      {/* Widget flottant */}
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className="fixed bottom-6 right-6 z-50 flex items-center gap-2 rounded-full bg-blue-600 px-5 py-3 text-white shadow-lg hover:bg-blue-700 transition-all hover:scale-105"
          aria-label="Parler avec Aurélia"
        >
          {showPulse && (
            <span className="absolute -top-1 -right-1 flex h-4 w-4">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-yellow-400 opacity-75" />
              <span className="relative inline-flex rounded-full h-4 w-4 bg-yellow-400" />
            </span>
          )}
          <Sparkles className="h-5 w-5" />
          <span className="text-sm font-medium">Aurélia</span>
        </button>
      )}

      {/* Fenetre de chat */}
      {isOpen && (
        <div className="fixed bottom-6 right-6 z-50 w-96 h-[32rem] flex flex-col rounded-2xl border bg-background shadow-2xl overflow-hidden">
          {/* Header */}
          <div className="flex items-center justify-between px-4 py-3 bg-blue-600 text-white">
            <div className="flex items-center gap-2">
              <Sparkles className="h-5 w-5" />
              <div>
                <p className="font-semibold text-sm">Aurélia</p>
                <p className="text-xs opacity-80">Tutrice personnelle</p>
              </div>
            </div>
            <div className="flex items-center gap-1">
              <button
                onClick={() => setAutoSpeak(prev => !prev)}
                className={`p-1 rounded transition-colors ${autoSpeak ? 'bg-blue-500' : 'hover:bg-blue-700 opacity-60'}`}
                aria-label={autoSpeak ? 'Désactiver la lecture automatique' : 'Activer la lecture automatique'}
                title={autoSpeak ? 'Lecture auto activée' : 'Lecture auto désactivée'}
              >
                {autoSpeak ? <Volume2 className="h-4 w-4" /> : <VolumeX className="h-4 w-4" />}
              </button>
              <button onClick={() => setIsOpen(false)} aria-label="Fermer" className="p-1 hover:bg-blue-700 rounded">
                <X className="h-5 w-5" />
              </button>
            </div>
          </div>

          {/* Context banner */}
          {context?.courseTitle && (
            <div className="px-3 py-1.5 bg-blue-50 text-xs text-blue-700 border-b">
              📖 {context.courseTitle} {context.lessonTitle ? `→ ${context.lessonTitle}` : ''}
            </div>
          )}

          {/* Province selector (shown once if province not set) */}
          {showProvincePrompt && !selectedProvince && (
            <div className="px-3 py-2 bg-amber-50 border-b border-amber-100">
              <p className="text-xs text-amber-700 font-medium mb-2">Dans quelle province travailles-tu?</p>
              <select
                value=""
                onChange={async (e) => {
                  const code = e.target.value;
                  if (!code) return;
                  setSelectedProvince(code);
                  setShowProvincePrompt(false);
                  // Save to profile
                  try {
                    await fetch('/api/lms/preferences', {
                      method: 'PUT',
                      headers: { 'Content-Type': 'application/json' },
                      body: JSON.stringify({ workProvince: code }),
                    });
                  } catch { /* silent */ }
                  const prov = PROVINCE_OPTIONS.find(p => p.code === code);
                  setMessages(prev => [
                    ...prev,
                    {
                      id: `province-${Date.now()}`,
                      role: 'assistant',
                      content: `Parfait! J'ai note que tu travailles en ${prov?.label || code}. Je vais adapter mes reponses aux lois et regulateurs de ta province. Pose-moi ta premiere question!`,
                      timestamp: new Date(),
                    },
                  ]);
                }}
                className="w-full px-2 py-1.5 border border-amber-200 rounded-lg text-sm bg-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                aria-label="Province de travail"
              >
                <option value="">Selectionner...</option>
                {PROVINCE_OPTIONS.map(p => (
                  <option key={p.code} value={p.code}>{p.label} ({p.code})</option>
                ))}
              </select>
            </div>
          )}

          {/* Messages */}
          <div className="flex-1 overflow-y-auto px-4 py-3 space-y-3">
            {messages.map((msg) => (
              <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className="flex flex-col gap-1 max-w-[80%]">
                  <div className={`rounded-2xl px-4 py-2 text-sm ${
                    msg.role === 'user'
                      ? 'bg-blue-600 text-white rounded-br-md'
                      : 'bg-muted rounded-bl-md'
                  }`}>
                    {msg.content}
                  </div>
                  {msg.role === 'assistant' && msg.id !== 'greeting' && (
                    <div className="flex items-center gap-1 px-1">
                      <button
                        onClick={() => speakMessage(msg.id, msg.content)}
                        disabled={loadingTtsId === msg.id}
                        className={`p-1 rounded-full transition-colors text-muted-foreground hover:text-blue-600 hover:bg-blue-50 disabled:opacity-50 ${
                          speakingMessageId === msg.id ? 'text-blue-600 bg-blue-50' : ''
                        }`}
                        aria-label={
                          loadingTtsId === msg.id
                            ? 'Chargement audio...'
                            : speakingMessageId === msg.id
                              ? 'Arrêter la lecture'
                              : 'Écouter ce message'
                        }
                        title={
                          loadingTtsId === msg.id
                            ? 'Chargement...'
                            : speakingMessageId === msg.id
                              ? 'Arrêter'
                              : 'Écouter'
                        }
                      >
                        {loadingTtsId === msg.id ? (
                          <Loader2 className="h-3.5 w-3.5 animate-spin" />
                        ) : speakingMessageId === msg.id ? (
                          <VolumeX className="h-3.5 w-3.5" />
                        ) : (
                          <Volume2 className="h-3.5 w-3.5" />
                        )}
                      </button>
                    </div>
                  )}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-muted rounded-2xl rounded-bl-md px-4 py-2 text-sm">
                  <span className="animate-pulse">Aurélia réfléchit...</span>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="border-t px-3 py-2 flex items-center gap-2">
            <button
              onClick={toggleVoice}
              className={`p-2 rounded-full transition-colors ${
                isListening ? 'bg-red-100 text-red-600 animate-pulse' : 'hover:bg-muted text-muted-foreground'
              }`}
              aria-label={isListening ? 'Arrêter l\'écoute' : 'Parler'}
            >
              {isListening ? <MicOff className="h-5 w-5" /> : <Mic className="h-5 w-5" />}
            </button>
            <input
              ref={inputRef}
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && sendMessage(input)}
              placeholder="Pose ta question..."
              className="flex-1 text-sm bg-muted rounded-full px-4 py-2 outline-none focus-visible:outline-2 focus-visible:outline-blue-500"
              aria-label="Message pour Aurélia"
            />
            <button
              onClick={() => sendMessage(input)}
              disabled={!input.trim() || isLoading}
              className="p-2 text-blue-600 hover:bg-blue-50 rounded-full disabled:opacity-30"
              aria-label="Envoyer"
            >
              <Send className="h-5 w-5" />
            </button>
          </div>
        </div>
      )}
    </>
  );
}

'use client';

import { useState, useCallback, useEffect, useRef } from 'react';
import { useTranslations } from '@/hooks/useTranslations';

// ── Types ────────────────────────────────────────────────────

export interface StudyTimerProps {
  /** Called when a study/break session finishes */
  onSessionEnd?: (sessionData: {
    type: 'focus' | 'break';
    durationMinutes: number;
    pomodoroNumber: number;
    totalStudyMinutes: number;
  }) => void;
  /** Default focus duration in minutes */
  defaultDuration?: number;
  /** Default break duration in minutes */
  defaultBreak?: number;
  /** Start in compact mode */
  compact?: boolean;
}

type TimerPhase = 'idle' | 'focus' | 'break';

// ── Component ───────────────────────────────────────────────

export default function StudyTimer({
  onSessionEnd,
  defaultDuration = 25,
  defaultBreak = 5,
  compact: initialCompact = false,
}: StudyTimerProps) {
  const { t } = useTranslations();

  const [phase, setPhase] = useState<TimerPhase>('idle');
  const [isRunning, setIsRunning] = useState(false);
  const [focusDuration, setFocusDuration] = useState(defaultDuration);
  const [breakDuration, setBreakDuration] = useState(defaultBreak);
  const [secondsLeft, setSecondsLeft] = useState(defaultDuration * 60);
  const [pomodoroCount, setPomodoroCount] = useState(0);
  const [totalStudySeconds, setTotalStudySeconds] = useState(0);
  const [isCompact, setIsCompact] = useState(initialCompact);
  const [showBreakSuggestion, setShowBreakSuggestion] = useState(false);

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  const totalSeconds = phase === 'break' ? breakDuration * 60 : focusDuration * 60;
  const progress = totalSeconds > 0 ? (totalSeconds - secondsLeft) / totalSeconds : 0;

  // ── Timer tick ────────────────────────────────────────────

  useEffect(() => {
    if (isRunning && secondsLeft > 0) {
      intervalRef.current = setInterval(() => {
        setSecondsLeft(prev => {
          if (prev <= 1) {
            clearInterval(intervalRef.current!);
            return 0;
          }
          return prev - 1;
        });
        if (phase === 'focus') {
          setTotalStudySeconds(prev => prev + 1);
        }
      }, 1000);
    }

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [isRunning, phase, secondsLeft]);

  // ── Handle timer reaching zero ────────────────────────────

  useEffect(() => {
    if (secondsLeft === 0 && isRunning) {
      setIsRunning(false);
      playNotificationSound();

      if (phase === 'focus') {
        const newCount = pomodoroCount + 1;
        setPomodoroCount(newCount);
        setShowBreakSuggestion(true);
        onSessionEnd?.({
          type: 'focus',
          durationMinutes: focusDuration,
          pomodoroNumber: newCount,
          totalStudyMinutes: Math.round(totalStudySeconds / 60),
        });
      } else if (phase === 'break') {
        onSessionEnd?.({
          type: 'break',
          durationMinutes: breakDuration,
          pomodoroNumber: pomodoroCount,
          totalStudyMinutes: Math.round(totalStudySeconds / 60),
        });
        // Auto-transition to next focus session
        setPhase('focus');
        setSecondsLeft(focusDuration * 60);
        setShowBreakSuggestion(false);
      }
    }
  }, [secondsLeft, isRunning, phase, pomodoroCount, focusDuration, breakDuration, totalStudySeconds, onSessionEnd]);

  // ── Sound ─────────────────────────────────────────────────

  const playNotificationSound = useCallback(() => {
    try {
      const ctx = audioContextRef.current || new AudioContext();
      audioContextRef.current = ctx;

      // Pleasant chime: two sine tones
      const playTone = (freq: number, startTime: number, duration: number) => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.frequency.value = freq;
        osc.type = 'sine';
        gain.gain.setValueAtTime(0, startTime);
        gain.gain.linearRampToValueAtTime(0.3, startTime + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration);
        osc.start(startTime);
        osc.stop(startTime + duration);
      };

      const now = ctx.currentTime;
      playTone(523.25, now, 0.4);       // C5
      playTone(659.25, now + 0.2, 0.4); // E5
      playTone(783.99, now + 0.4, 0.6); // G5
    } catch {
      // Audio not available — silent fallback
    }
  }, []);

  // Cleanup audio context on unmount
  useEffect(() => {
    return () => {
      audioContextRef.current?.close();
    };
  }, []);

  // ── Actions ───────────────────────────────────────────────

  const handleStart = useCallback(() => {
    if (phase === 'idle') {
      setPhase('focus');
      setSecondsLeft(focusDuration * 60);
    }
    setIsRunning(true);
    setShowBreakSuggestion(false);
  }, [phase, focusDuration]);

  const handlePause = useCallback(() => {
    setIsRunning(false);
  }, []);

  const handleReset = useCallback(() => {
    setIsRunning(false);
    setPhase('idle');
    setSecondsLeft(focusDuration * 60);
    setShowBreakSuggestion(false);
  }, [focusDuration]);

  const handleStartBreak = useCallback(() => {
    setPhase('break');
    setSecondsLeft(breakDuration * 60);
    setIsRunning(true);
    setShowBreakSuggestion(false);
  }, [breakDuration]);

  const handleSkipBreak = useCallback(() => {
    setPhase('focus');
    setSecondsLeft(focusDuration * 60);
    setShowBreakSuggestion(false);
  }, [focusDuration]);

  // ── Format time ───────────────────────────────────────────

  const formatTime = (s: number): string => {
    const m = Math.floor(s / 60);
    const sec = s % 60;
    return `${m.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}`;
  };

  // ── Break suggestions ────────────────────────────────────

  const breakActivities = [
    t('learn.studyTimer.breakStretch'),
    t('learn.studyTimer.breakWalk'),
    t('learn.studyTimer.breakWater'),
    t('learn.studyTimer.breakBreathe'),
    t('learn.studyTimer.breakEyes'),
  ];

  // Rotate suggestion based on pomodoro count
  const breakSuggestion = breakActivities[pomodoroCount % breakActivities.length];

  // ── SVG Circle ────────────────────────────────────────────

  const circleSize = isCompact ? 80 : 160;
  const strokeWidth = isCompact ? 4 : 6;
  const radius = (circleSize - strokeWidth * 2) / 2;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference * (1 - progress);

  const phaseColor = phase === 'break' ? '#22c55e' : '#3b82f6';
  const phaseColorLight = phase === 'break' ? '#dcfce7' : '#dbeafe';

  // ── Compact Mode ──────────────────────────────────────────

  if (isCompact) {
    return (
      <div className="fixed bottom-6 left-6 z-40">
        <button
          onClick={() => setIsCompact(false)}
          className="group relative flex items-center gap-3 rounded-full shadow-lg border border-gray-200 bg-white px-4 py-2 hover:shadow-xl transition-all"
          aria-label={t('learn.studyTimer.expand')}
        >
          {/* Mini circle */}
          <svg width={36} height={36} className="flex-shrink-0">
            <circle
              cx={18} cy={18} r={14}
              fill="none"
              stroke="#e5e7eb"
              strokeWidth={3}
            />
            <circle
              cx={18} cy={18} r={14}
              fill="none"
              stroke={phaseColor}
              strokeWidth={3}
              strokeDasharray={2 * Math.PI * 14}
              strokeDashoffset={2 * Math.PI * 14 * (1 - progress)}
              strokeLinecap="round"
              transform="rotate(-90 18 18)"
              className="transition-all duration-1000"
            />
          </svg>
          <div className="text-left">
            <div className="text-sm font-mono font-bold text-gray-900">{formatTime(secondsLeft)}</div>
            <div className="text-[10px] text-gray-400 font-medium">
              {phase === 'focus'
                ? t('learn.studyTimer.focusPhase')
                : phase === 'break'
                  ? t('learn.studyTimer.breakPhase')
                  : t('learn.studyTimer.idle')}
            </div>
          </div>
          {isRunning && (
            <span className="absolute -top-1 -right-1 w-3 h-3 rounded-full bg-green-500 animate-pulse" />
          )}
        </button>
      </div>
    );
  }

  // ── Full Mode ─────────────────────────────────────────────

  return (
    <div className="w-full max-w-sm mx-auto px-4 py-6">
      <div className="rounded-2xl bg-white shadow-lg border border-gray-100 p-6">
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <div>
            <h3 className="text-lg font-bold text-gray-900">{t('learn.studyTimer.title')}</h3>
            <p className="text-xs text-gray-400 mt-0.5">
              {phase === 'focus'
                ? t('learn.studyTimer.focusPhase')
                : phase === 'break'
                  ? t('learn.studyTimer.breakPhase')
                  : t('learn.studyTimer.idle')}
            </p>
          </div>
          <div className="flex items-center gap-2">
            {/* Pomodoro counter */}
            <div className="flex items-center gap-1">
              {Array.from({ length: Math.min(pomodoroCount, 8) }).map((_, i) => (
                <span key={i} className="w-2.5 h-2.5 rounded-full bg-red-400" />
              ))}
              {pomodoroCount > 8 && (
                <span className="text-xs text-gray-400 ml-1">+{pomodoroCount - 8}</span>
              )}
              {pomodoroCount === 0 && (
                <span className="text-xs text-gray-400">{t('learn.studyTimer.noPomodorosYet')}</span>
              )}
            </div>

            {/* Compact toggle */}
            <button
              onClick={() => setIsCompact(true)}
              className="w-7 h-7 rounded-lg bg-gray-100 hover:bg-gray-200 flex items-center justify-center text-gray-500 transition-colors"
              aria-label={t('learn.studyTimer.minimize')}
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
              </svg>
            </button>
          </div>
        </div>

        {/* Timer Circle */}
        <div className="flex items-center justify-center mb-6">
          <div className="relative">
            <svg width={circleSize} height={circleSize} className="transform -rotate-90">
              {/* Background circle */}
              <circle
                cx={circleSize / 2}
                cy={circleSize / 2}
                r={radius}
                fill="none"
                stroke="#f3f4f6"
                strokeWidth={strokeWidth}
              />
              {/* Progress circle */}
              <circle
                cx={circleSize / 2}
                cy={circleSize / 2}
                r={radius}
                fill="none"
                stroke={phaseColor}
                strokeWidth={strokeWidth}
                strokeDasharray={circumference}
                strokeDashoffset={strokeDashoffset}
                strokeLinecap="round"
                className="transition-all duration-1000 ease-linear"
              />
            </svg>
            {/* Time display */}
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-3xl font-mono font-bold text-gray-900">
                {formatTime(secondsLeft)}
              </span>
              {phase !== 'idle' && (
                <span
                  className="text-xs font-medium mt-1 px-2 py-0.5 rounded-full"
                  style={{ backgroundColor: phaseColorLight, color: phaseColor }}
                >
                  #{pomodoroCount + (phase === 'focus' ? 1 : 0)}
                </span>
              )}
            </div>
          </div>
        </div>

        {/* Duration config (only in idle) */}
        {phase === 'idle' && (
          <div className="grid grid-cols-2 gap-3 mb-6">
            <div>
              <label className="text-xs font-medium text-gray-500 mb-1 block">
                {t('learn.studyTimer.focusMinutes')}
              </label>
              <div className="flex items-center gap-1">
                {[15, 25, 45, 60].map(m => (
                  <button
                    key={m}
                    onClick={() => { setFocusDuration(m); setSecondsLeft(m * 60); }}
                    className={`flex-1 py-1.5 text-xs font-medium rounded-lg transition-colors ${
                      focusDuration === m
                        ? 'bg-blue-600 text-white'
                        : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    {m}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="text-xs font-medium text-gray-500 mb-1 block">
                {t('learn.studyTimer.breakMinutes')}
              </label>
              <div className="flex items-center gap-1">
                {[3, 5, 10, 15].map(m => (
                  <button
                    key={m}
                    onClick={() => setBreakDuration(m)}
                    className={`flex-1 py-1.5 text-xs font-medium rounded-lg transition-colors ${
                      breakDuration === m
                        ? 'bg-green-600 text-white'
                        : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    {m}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Break suggestion */}
        {showBreakSuggestion && (
          <div className="mb-6 rounded-xl bg-green-50 border border-green-200 p-4 text-center">
            <p className="text-sm font-semibold text-green-800 mb-1">
              {t('learn.studyTimer.pomodoroComplete')}
            </p>
            <p className="text-xs text-green-600 mb-3">
              {breakSuggestion}
            </p>
            <div className="flex items-center gap-2 justify-center">
              <button
                onClick={handleStartBreak}
                className="px-4 py-2 text-xs font-semibold bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors"
              >
                {t('learn.studyTimer.takeBreak', { minutes: breakDuration })}
              </button>
              <button
                onClick={handleSkipBreak}
                className="px-4 py-2 text-xs font-semibold text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors"
              >
                {t('learn.studyTimer.skipBreak')}
              </button>
            </div>
          </div>
        )}

        {/* Controls */}
        <div className="flex items-center justify-center gap-3">
          {!isRunning && phase !== 'break' && !showBreakSuggestion && (
            <button
              onClick={handleStart}
              className="inline-flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-semibold rounded-xl hover:bg-blue-700 transition-colors active:scale-95"
              aria-label={t('learn.studyTimer.start')}
            >
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                <path d="M8 5v14l11-7z" />
              </svg>
              {phase === 'idle' ? t('learn.studyTimer.start') : t('learn.studyTimer.resume')}
            </button>
          )}

          {isRunning && (
            <button
              onClick={handlePause}
              className="inline-flex items-center gap-2 px-6 py-3 bg-gray-600 text-white font-semibold rounded-xl hover:bg-gray-700 transition-colors active:scale-95"
              aria-label={t('learn.studyTimer.pause')}
            >
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                <path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z" />
              </svg>
              {t('learn.studyTimer.pause')}
            </button>
          )}

          {phase !== 'idle' && (
            <button
              onClick={handleReset}
              className="inline-flex items-center gap-2 px-4 py-3 text-gray-500 font-medium rounded-xl hover:bg-gray-100 transition-colors active:scale-95"
              aria-label={t('learn.studyTimer.reset')}
            >
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              {t('learn.studyTimer.reset')}
            </button>
          )}
        </div>

        {/* Stats footer */}
        {(pomodoroCount > 0 || totalStudySeconds > 0) && (
          <div className="mt-6 pt-4 border-t border-gray-100 flex items-center justify-around text-center">
            <div>
              <div className="text-lg font-bold text-gray-900">{pomodoroCount}</div>
              <div className="text-[10px] font-medium text-gray-400 uppercase tracking-wider">
                {t('learn.studyTimer.sessions')}
              </div>
            </div>
            <div className="w-px h-8 bg-gray-200" />
            <div>
              <div className="text-lg font-bold text-gray-900">{Math.round(totalStudySeconds / 60)}</div>
              <div className="text-[10px] font-medium text-gray-400 uppercase tracking-wider">
                {t('learn.studyTimer.minutesStudied')}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
